import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet, RouterLink, RouterLinkActive, ActivatedRoute } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { SiteviewService } from '../../core/services/siteview.service';

@Component({
  selector: 'app-project-shell',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: './project-shell.component.html',
  styleUrl: './project-shell.component.css',
})
export class ProjectShellComponent {
  private readonly projectId = toSignal(
    this.route.paramMap.pipe(map((p) => p.get('id') ?? '')),
    { initialValue: this.route.snapshot.paramMap.get('id') ?? '' },
  );

  readonly project = computed(() => this.sv.getProject(this.projectId()));
  readonly notFound = computed(() => !this.project());

  readonly tabs = signal([
    { path: 'dashboard', label: 'Dashboard', icon: '📊' },
    { path: 'schedule', label: 'Schedule', icon: '📅' },
    { path: 'milestones', label: 'Milestones', icon: '🚩' },
    { path: 'budget', label: 'Budget', icon: '💰' },
    { path: 'siteplan', label: 'Site Plan', icon: '🗺️' },
  ]);

  constructor(
    private sv: SiteviewService,
    private route: ActivatedRoute,
  ) {}
}
